/*
 * storeUtils.ts
 * store 관련 유틸들(파생 타입, 생성 함수들) 있는 모듈
 */
import { writable } from 'svelte/store';
import { addStats } from "../stats";
//초기값을 initial로 하고, add, sub, reset, getDefault 있는 Writable<number>를 생성하는 함수
export const createNumber = (initial) => {
    const { subscribe, set, update } = writable(initial);
    return {
        subscribe,
        set,
        update,
        add: (e) => {
            update(n => n + e);
        },
        sub: (e) => {
            update(n => n - e);
        },
        reset: () => {
            set(initial);
        },
        getDefault: () => initial
    };
};
//초기값을 initial로 하고, add, reset, getDefault 있는 Writable<Stats>를 생성하는 함수
export const createStats = (initial) => {
    const { subscribe, set, update } = writable(Object.assign({}, initial));
    return {
        subscribe,
        set,
        update,
        add: (e) => {
            update(n => addStats(n, e));
        },
        reset: () => {
            set(Object.assign({}, initial));
        },
        getDefault: () => (Object.assign({}, initial))
    };
};
//초기값을 initial로 하고, add, reset, getDefault 있는 Writable<string[]>을 생성하는 함수
export const createList = (initial) => {
    const { subscribe, set, update } = writable([...initial]);
    return {
        subscribe,
        set,
        update,
        add: (e) => {
            update(n => [...n, ...e]);
        },
        reset: () => {
            set([...initial]);
        },
        getDefault: () => ([...initial])
    };
};
